const payloadStr = (typeof msg.payload === 'string') ? msg.payload : msg.payload.toString();

if (payloadStr.includes('slowAES.decrypt')) {
    node.warn("ProFreeHost Bot Challenge Detected. Calculating bypass cookie...");

    const regexA = /var a=toNumbers\("([a-f0-9]+)"\)/;
    const regexB = /var b=toNumbers\("([a-f0-9]+)"\)/;
    const regexC = /var c=toNumbers\("([a-f0-9]+)"\)/;

    const matchA = payloadStr.match(regexA);
    const matchB = payloadStr.match(regexB);
    const matchC = payloadStr.match(regexC);

    if (matchA && matchB && matchC) {
        const key = Buffer.from(matchA[1], 'hex');
        const iv = Buffer.from(matchB[1], 'hex');
        const cipherText = Buffer.from(matchC[1], 'hex');

        const crypto = require('crypto');
        const decipher = crypto.createDecipheriv('aes-128-cbc', key, iv);
        decipher.setAutoPadding(false);

        let decrypted = decipher.update(cipherText);
        decrypted = Buffer.concat([decrypted, decipher.final()]);

        const testCookie = decrypted.toString('hex');

        if (!msg.headers) msg.headers = {};
        msg.headers['Cookie'] = `__test=${testCookie}`;

        // Loop back original saved payload so we can resend
        msg.payload = msg.originalPayload || msg.payload;

        return [msg, null];
    }
}

return [null, msg];
